    || ' :class="{ ''ops-terminal-status--reconnecting'': s._reconnecting, ''ops-terminal-status--backpressure'': s._backpressure }">'
    || '<span x-text="s._backpressure ? ''Buffer plein...'' : s._reconnecting ? ''Reconnexion...'' : ''Connexion...''"></span>'
    || '</div>'
    || '</div>'
    || '</div>'
    || '</article>'
    || '</template>'
    || '</div>'
    || '</div>';

  RETURN v_body;
