GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA ops TO web_anon;

-- Schema: ops_ut
CREATE SCHEMA IF NOT EXISTS ops_ut;

CREATE OR REPLACE FUNCTION ops_ut.test_filtered_views()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- get_messages with filter
  v_html := ops.get_messages('cad');
  RETURN NEXT ok(v_html IS NOT NULL, 'get_messages(cad) returns HTML');

  -- get_messages with non-existent module -> empty state
  v_html := ops.get_messages('nonexistent_xyz');
  RETURN NEXT ok(v_html LIKE '%pgv-empty%', 'get_messages(nonexistent) shows empty state');

  -- get_hooks with filter
  v_html := ops.get_hooks('cad');
  RETURN NEXT ok(v_html IS NOT NULL, 'get_hooks(cad) returns HTML');

  -- get_hooks with non-existent module -> empty state
  v_html := ops.get_hooks('nonexistent_xyz');
  RETURN NEXT ok(v_html LIKE '%pgv-empty%', 'get_hooks(nonexistent) shows empty state');

  -- get_agent with non-existent module -> still renders (stats will be 0)
  v_html := ops.get_agent('nonexistent_xyz');
  RETURN NEXT ok(v_html IS NOT NULL, 'get_agent(nonexistent) renders without error');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_agent(nonexistent) still shows stat widgets');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_filtered_views() IS 'Test get_messages and get_hooks with module filter and edge cases';

CREATE OR REPLACE FUNCTION ops_ut.test_get_agents()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_agents();
  RETURN NEXT ok(v_html IS NOT NULL AND length(v_html) > 0, 'get_agents renders HTML');
  RETURN NEXT ok(v_html LIKE '%opsTmuxGrid%', 'get_agents contains Alpine grid component');
  RETURN NEXT ok(v_html LIKE '%ops-agent-card%', 'get_agents contains card structure');
  RETURN NEXT ok(v_html LIKE '%ops-agent-chevron%', 'get_agents contains chevron');
  RETURN NEXT ok(v_html LIKE '%ops-agent-status%', 'get_agents contains status span');
  RETURN NEXT ok(v_html LIKE '%expandAll()%', 'get_agents has expand all button');
  RETURN NEXT ok(v_html LIKE '%collapseAll()%', 'get_agents has collapse all button');
  RETURN NEXT ok(v_html LIKE '%pgv-empty%', 'get_agents has empty state fallback');
  -- No inline styles
  RETURN NEXT ok(v_html NOT LIKE '%style="%', 'get_agents has no inline styles');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_get_agents() IS 'Test get_agents renders collapsible card structure with Alpine.js bindings';

CREATE OR REPLACE FUNCTION ops_ut.test_get_dashboard()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_dashboard();
  RETURN NEXT ok(v_html IS NOT NULL AND length(v_html) > 0, 'get_dashboard renders HTML');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_dashboard contains stat widgets');
  RETURN NEXT ok(v_html LIKE '%Fonctions%', 'get_dashboard shows total functions');
  RETURN NEXT ok(v_html LIKE '%Tests%', 'get_dashboard shows total tests');
  RETURN NEXT ok(v_html LIKE '%cad%', 'get_dashboard lists cad module');
  -- No inline styles
  RETURN NEXT ok(v_html NOT LIKE '%style="%', 'get_dashboard has no inline styles');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_get_dashboard() IS 'Test get_dashboard renders health overview with stats and module table';

CREATE OR REPLACE FUNCTION ops_ut.test_get_message()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_id int;
BEGIN
  -- Get a real message id
  SELECT id INTO v_id FROM workbench.agent_message ORDER BY created_at DESC LIMIT 1;

  IF v_id IS NOT NULL THEN
    v_html := ops.get_message(v_id);
    RETURN NEXT ok(v_html IS NOT NULL AND length(v_html) > 0, 'get_message renders HTML for existing msg');
    RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_message shows stat widgets');
    RETURN NEXT ok(v_html LIKE '%breadcrumb%' OR v_html LIKE '%Messages%', 'get_message has breadcrumb');
    RETURN NEXT ok(v_html NOT LIKE '%style="%', 'get_message has no inline styles');
  ELSE
    RETURN NEXT ok(true, 'no messages in DB — skip detail test');
  END IF;

  -- Not found
  v_html := ops.get_message(-999);
  RETURN NEXT ok(v_html LIKE '%pgv-empty%', 'get_message(-999) shows empty state');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_get_message() IS 'Test get_message detail page — existing message and not found';

CREATE OR REPLACE FUNCTION ops_ut.test_get_modules()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_modules();
  RETURN NEXT ok(v_html IS NOT NULL AND length(v_html) > 0, 'get_modules renders HTML');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_modules contains stat widgets');
  RETURN NEXT ok(v_html LIKE '%Modules%', 'get_modules shows module count');
  RETURN NEXT ok(v_html LIKE '%Fonctions%', 'get_modules shows function count');
  RETURN NEXT ok(v_html LIKE '%Tests%', 'get_modules shows test count');
  RETURN NEXT ok(v_html LIKE '%cad%', 'get_modules lists cad module');
  RETURN NEXT ok(v_html LIKE '%crm%', 'get_modules lists crm module');
  -- No inline styles
  RETURN NEXT ok(v_html NOT LIKE '%style="%', 'get_modules has no inline styles');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_get_modules() IS 'Test get_modules affiche la registry avec stats et badge nouveau';

CREATE OR REPLACE FUNCTION ops_ut.test_module_list()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_index();
  RETURN NEXT ok(length(v_html) > 100, 'get_index returns substantial HTML (uses _module_list)');
  RETURN NEXT ok(v_html LIKE '%cad%', 'get_index contains cad module card');
  -- New global stats
  RETURN NEXT ok(v_html LIKE '%Fonctions%', 'get_index shows total functions');
  RETURN NEXT ok(v_html LIKE '%Tests%', 'get_index shows total tests');
  RETURN NEXT ok(v_html LIKE '%Taches resolues%', 'get_index shows resolved tasks');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_module_list() IS 'Test _module_list et stats globales sur get_index';

CREATE OR REPLACE FUNCTION ops_ut.test_module_stats()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_agent('cad');
  RETURN NEXT ok(v_html IS NOT NULL, 'get_agent(cad) returns HTML');
