CREATE OR REPLACE FUNCTION ops_ut.test_pages_render()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT ok(length(ops.get_index()) > 0, 'get_index renders HTML');
  RETURN NEXT ok(length(ops.get_modules()) > 0, 'get_modules renders HTML');
  RETURN NEXT ok(length(ops.get_messages()) > 0, 'get_messages renders HTML');
  RETURN NEXT ok(length(ops.get_hooks()) > 0, 'get_hooks renders HTML');
  RETURN NEXT ok(length(ops.get_agent('cad')) > 0, 'get_agent renders HTML');

  -- Navigation
  RETURN NEXT ok(ops.brand() = 'Ops', 'brand returns Ops');
  RETURN NEXT ok(
    (ops.nav_items())::text LIKE '%Dashboard%',
    'nav_items contains Dashboard'
  );
  RETURN NEXT ok(
    (ops.nav_items())::text LIKE '%Modules%',
    'nav_items contains Modules'
  );
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_pages_render() IS 'Test toutes les pages retournent du HTML non-vide';

CREATE OR REPLACE FUNCTION ops_ut.test_recent_events()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- The dashboard shows recent events from hook_log and agent_message
  -- We have hook events from this session already
  v_html := ops.get_index();
  RETURN NEXT ok(v_html LIKE '%Activite recente%', 'get_index shows recent events section');
  RETURN NEXT ok(v_html LIKE '%hook%' OR v_html LIKE '%message%', 'timeline contains event badges');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_recent_events() IS 'Test _recent_events via le dashboard qui affiche la timeline';

